INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('绩效跃升部实习生 - 福州（实习）', '制造', '福州', '外资企业', 100, 120, '1. 具备良好的英语口语及书面表达能力；2. 擅长数据分析及报告制作；3. 熟练使用Word、Excel、PPT、OA办公软件', '1. 工作认真主动，态度积极，有较强的责任心，善于沟通；2. 有较强的抗压能力，善于学习，具有独立解决问题的能力；3. 具备良好的跨部门协同能力与执行力', 1, '极度友好', '1. 协助跨部门协同工作，传递工作信息、跟进协同事项进展；2. 协助跨部门会议，进行各项工作的日程跟踪及闭环落地；3. 协助部门、绩效跃升、增程车型相关文档报告的汇整、归档与管理工作；4. 协助开展成本管控相关辅助工作；5. 协助部门日常工作推进、协助上级领导安排的任务', '薪酬绩效支持', '本科及以上', '无强制专业限制', '可实习5个月，每周到岗5天', '日常实习', '有汽车行业、绩效相关实习经验者优先', '100-120元/天', '46112', '46421', 'https://www.shixiseng.com/intern/inn_weskuuic0lp?pcm=pc_SearchList', '薪酬绩效类', '甲方（企业自有 HR 岗）'), ('绩效运营实习生 - 北京（实习）', '互联网 / IT', '北京', '民营企业', 200, 250, '1. 熟练使用办公软件，有良好的数据分析能力，对数据敏感，逻辑思维强；2. 具备基础的数据整理、分析与报告制作能力；3. 熟练使用Excel进行数据处理', '1. 工作积极主动，耐心细致，责任心强；2. 良好的学习能力和执行力，具有较强的沟通表达能力，可以与其他部门进行快速对接；3. 具备良好的抗压能力与结果导向思维', 1, '极度友好', '1. 绩效激励规则宣贯与核算：负责激励、绩效核算，包含核验绩效指标达成情况与绩效结果统计支持；2. 销售运营：跟进业务团队核心指标达成进度，激励进度达成与过程数据通晒，包含优秀标杆打造；3. 激励绩效方案的培训宣导：深入一线收集绩效考核相关问题，定期监控绩效数据，评估执行效果，提出改进措施以提高销售绩效；4. 销售支持：负责销售数据的收集、整理和分析，为销售团队提供决策支持；5. 销售工具建设：包含销售提效工具建设与销售流程优化', '薪酬绩效支持、招聘数据分析', '本科及以上', '无强制专业限制', '可实习3个月，每周到岗5天，经验不限', '日常实习', '具有销售运营、绩效运营、数据运营、数据分析、数据产品的实习经历优先', '200-250元/天', '46112', '46131', 'https://www.shixiseng.com/intern/inn_aapbfhv0aq?pcm=pc_SearchList', '薪酬绩效类', '甲方（企业自有 HR 岗）'), ('绩效与薪酬管理咨询实习生 - 上海（实习）', '人力资源服务 / 咨询', '上海', '外资企业', 100, 120, '1. 熟练使用Office系列软件，擅长Excel数据处理与分析（如函数、透视表、图表制作等）；2. 具备PPT排版设计与审美能力；3. 具备基础的资料搜集、数据处理与可视化能力', '1. 具备优秀的信息整合和逻辑思维，注重细节、责任心强；2. 善于沟通与团队协作；3. 对咨询行业有强烈兴趣，具备快速学习能力和主动解决问题的态度', 1, '极度友好', '1. 深度参与咨询项目，协助顾问开展行业研究与数据分析，独立负责资料搜集、数据处理和可视化，洞察人力资源与薪酬领域的核心趋势；2. 参与深度行业研究与结果洞察，锻炼逻辑表达与商业洞察能力，成果将直接服务于客户决策；3. 支持项目全流程运作，包括客户需求沟通、会议协办与工作坊准备，近距离实战学习咨询项目的推进方法；4. 参与企业内部文档、合同及知识管理，培养专业顾问的底层工作素养与高效协作习惯', '薪酬绩效支持、招聘数据分析', '本科及以上', '无强制专业限制', '本科或研究生在读，可实习3个月，每周到岗3天', '日常实习', '有人力资源、管理咨询相关实习经验者优先', '100-120元/天', '46112', '46122', 'https://www.shixiseng.com/intern/inn_bwkdstcxjml?pcm=pc_SearchList', '薪酬绩效类', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('项目助理（政府预算绩效咨询） - 北京（实习）', '人力资源服务 / 咨询', '北京', '民营企业', 100, 200, '1. 熟练使用 Office 等办公软件及办公设备；2. 具备良好的文字功底，较强的逻辑思维能力与分析解决问题能力；3. 具备基础的文档撰写、排版与校对能力', '1. 具有较强的学习能力、应变能力、适应能力，沟通协调能力、团队合作精神；2. 具有强烈的责任心、学习能力和敬业精神，抗压能力强，能适应长期出差；3. 工作认真负责，严谨细致，保密意识强', 1, '友好', '1. 协助上级咨询人员开展预算绩效管理相关咨询服务工作，服从上级统一安排，配合完成项目各环节辅助任务；2. 协助收集、整理预算绩效管理相关政策文件、行业案例、基础数据等资料，按要求进行分类、归档，确保资料的完整性和准确性；3. 辅助完成咨询报告、方案草案、调研问卷等材料的录入、校对、排版工作，协助优化内容表述，确保文档规范、无误；4. 配合上级开展调研工作，协助做好调研记录、数据统计与初步分析，整理调研成果，为咨询方案制定提供基础支持；5. 协助对接客户及相关合作方，传递基础咨询、反馈简单咨询需求，做好沟通记录，及时向上级汇报沟通情况；6. 学习预算绩效管理相关专业知识，咨询工作流程和方法，主动配合上级完成其他临时性工作任务，提升自身专业能力；7. 严格遵守公司规章制度及项目保密要求，妥善保管咨询项目相关资料，不泄露工作机密', '薪酬绩效支持、招聘数据分析', '本科及以上', '会计学、财政学、经济、金融、项目管理、财务管理等专业', '可实习3个月，每周到岗5天，接受大一、大二在校生，零基础可实习', '日常实习', '有政府咨询、绩效咨询相关实习经验者优先', '100-200元/天', '46092', '46122', 'https://www.shixiseng.com/intern/inn_mdmgkv9nthfe?pcm=pc_SearchList', '薪酬绩效类', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('HRBP - 北京（校招）', '制造', '北京', '民营企业', 6000, 10000, '1. 掌握常用的面试方法和人力资源相关知识，了解国家和地方的相关劳动法律法规；2. 熟练使用Office办公软件', '1. 具备良好的团队合作精神、责任心和上进心，沟通能力强，能承受较大工作压力；2. 态度端正，认真负责并具有较强的执行力，具备一定独立分析及解决问题的能力；3. 良好的人际理解力，开放的心态和主动的学习意识', 1, '友好', '1. 协助所支持业务线的团队招聘工作；2. 参与组织绩效和员工绩效的落地执行；3. 主动与管理层、员工互动，多形式有效沟通，确保内部信息的有效传递；4. 协助管理者有效管理团队，包括团队建设、员工关怀、员工激励、员工关系等；5. 推动人力资源相关项目在业务部门落地', '招聘全流程执行、简历筛选与面试、员工关系支持、薪酬绩效支持、OD 组织发展支持', '本科及以上', '人力资源/管理类/理工科专业优先', '2025届应届生', '应届生校招', '有汽车行业、HR相关实习经验者优先', '6k-10k/月', '45717', '46112', 'https://www.shixiseng.com/intern/inn_lfkiepxlg0ug?pcm=pc_SearchList', 'HRBP类', '甲方（企业自有 HR 岗）');